// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract GrandGooseMansion {
    address private _owner;
    uint256 public supply;
    uint256 public cost;
    uint256 public maxSupply;
    uint256 public preSaleWalletLimit;
    mapping(address => uint256) public preSaleWalletMinted;
    enum SaleStatus { Paused, Presale, PublicSale }
    SaleStatus public currentSaleStatus;

    mapping(address => bool) private _whitelist;

    event Minted(address indexed minter, uint256 amount);

    constructor(
        uint256 initialSupply,
        uint256 initialCost,
        uint256 initialMaxSupply,
        uint256 initialPreSaleWalletLimit
    ) {
        _owner = msg.sender;
        supply = initialSupply;
        cost = initialCost;
        maxSupply = initialMaxSupply;
        preSaleWalletLimit = initialPreSaleWalletLimit;
        currentSaleStatus = SaleStatus.Paused;
    }

    modifier onlyOwner() {
        require(msg.sender == _owner, "Not owner");
        _;
    }

    function isWhitelisted(address user) public view returns (bool) {
        return _whitelist[user];
    }

    function whitelistUser(address user, bool status) public onlyOwner {
        _whitelist[user] = status;
    }

    function startPresale() public onlyOwner {
        require(currentSaleStatus != SaleStatus.PublicSale, "Already public sale");
        currentSaleStatus = SaleStatus.Presale;
    }

    function startPublicSale() public onlyOwner {
        require(currentSaleStatus != SaleStatus.PublicSale, "Already public sale");
        currentSaleStatus = SaleStatus.PublicSale;
    }

    function setCost(uint256 newCost) public onlyOwner {
        cost = newCost;
    }

    function mintTokenWhitelisted(uint256 amount) public payable {
        require(currentSaleStatus == SaleStatus.Presale, "Presale not active");
        require(isWhitelisted(msg.sender), "Not whitelisted");
        require(amount > 0, "Amount must be greater than zero");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(preSaleWalletMinted[msg.sender] + amount <= preSaleWalletLimit, "Exceeds wallet limit");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        preSaleWalletMinted[msg.sender] += amount;
        emit Minted(msg.sender, amount);
    }

    function mintTokenPublic(uint256 amount) public payable {
        require(currentSaleStatus == SaleStatus.PublicSale, "Public sale not active");
        require(amount > 0, "Amount must be greater than zero");
        require(supply + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * cost, "Exact payment required");

        supply += amount;
        emit Minted(msg.sender, amount);
    }
}
